                          ? 'text-blue-600 bg-blue-50/50'
                          : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'
                      }`}
                    >
                      <div className="flex items-center gap-3">
                        <item.icon className={`w-4 h-4 ${isActive && !hasChildren ? 'text-white' : ''}`} />
